import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    if len(unvisited_customers) == 0:
        return None  # or return the index to depot if needed

    # Time till each customer window closes, priority is inverse to amount of time left, adding soft margins
    remaining_time_windows = [max(0, tw[1] - current_time) for tw in time_windows]

    distances_to_customers = [calculate_distance(cur_truck_pos, customer) for customer in unvisited_customers]
    time_to_reach_customers = [dist / truck_speed for dist in distances_to_customers]

    # Score for each customer based on distance and urgency
    scores = []
    for i, (distance, time_left) in enumerate(zip(time_to_reach_customers, remaining_time_windows)):
        if time_left == 0:
            urgency_score = float('inf')  # Very urgent, need to go
        else:
            urgency_score = (time_left - time_to_reach_customers[i]) 

        # Combine scores: More urgent destinations get lower (better) scores, same with closer ones
        scores.append(distance + (-10 * urgency_score if urgency_score < 0 else 5 * urgency_score))

    # Choose customer with the lowest score
    best_node = np.argmin(scores)

    return best_node

