def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    def calculate_arrival_time(truck_pos, customer_pos):
        return current_time + (distance(truck_pos, customer_pos) / truck_speed)

    min_weight = float('inf')
    best_node = None

    for i, customer in enumerate(unvisited_customers):
        arrival_time = calculate_arrival_time(cur_truck_pos, customer)
        start_window, end_window = time_windows[i]

        # calculate penalty for time window deviations
        if arrival_time < start_window:
            wait_time = start_window - arrival_time
            time_penalty = wait_time  # penalty for arriving too early is the wait time
        elif arrival_time > end_window:
            time_penalty = (arrival_time - end_window) * 10  # heavier penalty for arriving too late
        else:
            time_penalty = 0  # no penalty within time window

        # Calculate urgency based on the closeness of arrival time to window end
        urgency_weight = (end_window - arrival_time) if arrival_time <= end_window else float('inf')

        # Calculate distance weight inversely related to the distance
        distance_weight = distance(cur_truck_pos, customer)

        # Total weight combines distance and penalties
        total_weight = (time_penalty + distance_weight) + 0.5 * urgency_weight

        if total_weight < min_weight:
            min_weight = total_weight
            best_node = i

    # If no node found viable, pick the closest node that can minimize future penalties
    if best_node is None:
        closest_distance = float('inf')
        closest_index = None
        for i, customer in enumerate(unvisited_customers):
            curr_distance = distance(cur_truck_pos, customer)
            if curr_distance < closest_distance:
                closest_distance = curr_distance
                closest_index = i
        best_node = closest_index

    return best_node

