def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.sqrt((p1[0] - p2[0])**2 + (p1[1] - p2[1])**2)

    min_time_to_arrive = []
    for idx, customer_pos in enumerate(unvisited_customers):
        distance = calculate_distance(cur_truck_pos, customer_pos)
        travel_time = distance / truck_speed
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[idx]

        if arrival_time < start_window:
            wait_time = start_window - arrival_time
            effective_time = travel_time + wait_time
        elif arrival_time > end_window:
            effective_time = travel_time + (arrival_time - end_window) * 10  # Large penalty for missing time window
        else:
            effective_time = travel_time

        min_time_to_arrive.append(effective_time + np.random.uniform(0, 0.1))  # Adding randomness to avoid always picking the same type of node

    best_node = np.argmin(min_time_to_arrive)
    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(start, end):
        return np.linalg.norm(start - end) / truck_speed

    def time_till_window(time_window):
        start, end = time_window
        return max(0, start - current_time), max(0, end - current_time)

    best_score = float('inf')
    best_node = None

    for idx, customer_pos in enumerate(unvisited_customers):
        travel_time_to_customer = travel_time(cur_truck_pos, customer_pos)
        wait_time_start, wait_time_end = time_till_window(time_windows[idx])

        if wait_time_start > travel_time_to_customer:
            penalty_time = (wait_time_start - travel_time_to_customer)
        else:
            penalty_time = 0

        score = penalty_time + travel_time_to_customer + wait_time_end

        if current_time + travel_time_to_customer > time_windows[idx][1]:
            score += 10000  # Large penalty for missing the time window

        # If the score is improved without waiting at the current position too long
        if score < best_score and penalty_time < 60:  # Allow waiting for up to 60 minutes
            best_score = score
            best_node = idx

    return best_node
